def chat_gemini_http(client, model: str, text: str, image_path, retry=1, temperature=0.6, max_tokens=8000):
    import base64
    import pathlib
    import time
    import requests
    import mimetypes
    api_key = client.api_key
    base_url = str(client.base_url)
    # 2. 构造 Gemini 原生 API URL
    # 假设中转平台支持 /models/{model}:generateContent 这种原生路由
    # 逻辑与 chat_video_gemini_http 保持一致
    url = base_url.rstrip("/") + f"/models/{model}:generateContent"

    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }
    # 3. 准备 Payload (Text + Image)
    parts = [{"text": text}]

    if image_path:
        try:
            # 自动推断图片 mime type (如 image/jpeg, image/png)
            mime_type, _ = mimetypes.guess_type(image_path)
            if not mime_type:
                mime_type = "image/jpeg" # 默认 fallback

            b64_data = base64.b64encode(pathlib.Path(image_path).read_bytes()).decode("utf-8")

            # Gemini 原生格式使用 inlineData
            parts.append({
                "inlineData": {
                    "mimeType": mime_type,
                    "data": b64_data
                }
            })
        except Exception as e:
            print(f"[QA-ERROR] Read Image Failed {image_path}: {e}", flush=True)
            return None
    payload = {
        "contents": [{
            "role": "user",
            "parts": parts
        }],
        "generationConfig": {
            "thinkingConfig": {
                "thinkingLevel": "low"
            },
            "temperature": temperature,
            "maxOutputTokens": max_tokens
        }
    }
    # 4. 发送请求与重试逻辑
    last_error = None
    for i in range(retry):
        try:
            response = requests.post(url, headers=headers, json=payload, timeout=60)

            if response.status_code == 200:
                data = response.json()

                # 解析 Gemini 原生响应结构
                if "candidates" in data and len(data["candidates"]) > 0:
                    content_parts = data["candidates"][0].get("content", {}).get("parts", [])
                    return "".join(p.get("text", "") for p in content_parts if "text" in p)

                # 兼容部分中转站可能直接返回 output_text 的情况
                if "output_text" in data:
                    return data["output_text"]

                return str(data) # 无法解析时返回原始数据字符串

            last_error = f"{response.status_code} {response.text}"

        except Exception as e:
            last_error = str(e)

        # 失败等待
        time.sleep(1.5 * (i + 1))
    print(f"[QA-ERROR] {image_path}: {last_error}", flush=True)
    return None

